sql:
SELECT COUNT(key_id) 
FROM cryptographic_keys 
WHERE key_status = 'active' AND key_expiration_date BETWEEN DATE('now') AND DATE('now', '+30 days');

SELECT DISTINCT key_type
FROM cryptographic_keys
WHERE key_status = 'active';

SELECT COUNT(key_id) AS num_keys_owned
FROM key_owners
WHERE owner_role = 'admin';

SELECT revocation_reason 
FROM key_revocation 
WHERE revocation_reason = 'security compromise';

SELECT COUNT(key_id) AS compromised_keys
FROM key_revocation 
WHERE revocation_reason = 'security_compromise';

external_knowledge:
- "Active keys" are those keys whose status is marked as 'active' in the `cryptographic_keys` table;
- "Most frequently used" refers to the key with the highest usage count for each service;
- "Accessed more than once" means the key has more than one entry in the `key_access_logs` table.

sql:
SELECT key_id
FROM key_usage
WHERE service_name = 'Payment Gateway' AND usage_type = 'encryption';

SELECT key_id
FROM key_usage
WHERE usage_count > (SELECT AVG(usage_count) FROM key_usage);

external_knowledge:
